Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,52 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  const equals = {}
+
+  // First pass: extract equals-pair flags
+  for (const arg of argv) {
+    if (arg.startsWith('--') && arg.includes('=')) {
+      const idx = arg.indexOf('=')
+      const key = arg.slice(2, idx)
+      equals[key] = arg.slice(idx + 1)
+    }
   }
+
+  // Second pass: handle flags and positionals
+  const processed = new Set()
+  const flags = []
+
+  for (let i = 0; i < argv.length; i++) {
+    const arg = argv[i]
+    
+    if (arg.startsWith('--')) {
+      const key = arg.slice(2)
+      
+      if (equals[key]) {
+        // Already handled as equals-pair
+        if (!processed.has(key)) {
+          result[key] = equals[key]
+        }
+      } else if (!processed.has(key)) {
+        // Boolean flag awaiting value
+        flags.push({ key, val: null })
+      }
+      processed.add(key)
+    } else {
+      result._.push(arg)
+      
+      // This positional might be a value for the last flag
+      if (flags.length > 0) {
+        flags[flags.length - 1].val = arg
+        result[flags[flags.length - 1].key] = arg
+        flags.pop()
+      }
+    }
+  }
+  
+  // Handle any remaining boolean flags
+  for (const { key } of flags) {
+    result[key] = true
+  }
+
   return result
 }

